    public void Initialize(ConstructionSessionV3 construction,ResourceSessionV3 resources,FarmSessionV3? farm,IMercenaryNavigationWorldQueryV3 query,WorldV2GridRenderer grid,WorldManagerV2 manager){_construction=construction;_resources=resources;_farm=farm;_query=query;_grid=grid;_manager=manager;ZIndex=0;QueueRedraw();}
