    public bool TryHandleInput(InputEvent e){if(!IsActive)return false;if(e is InputEventKey key&&key.Pressed&&!key.Echo&&key.Keycode==Key.Escape){SetTool(FloorToolModeV3.None);return true;}if(e is InputEventMouseButton right&&right.Pressed&&right.ButtonIndex==MouseButton.Right){SetTool(FloorToolModeV3.None);return true;}if(e is InputEventMouseMotion motion){if(_dragging)UpdatePreview(ScreenCell(motion.Position));return _dragging;}if(e is InputEventMouseButton left&&left.ButtonIndex==MouseButton.Left){GlobalCellCoord cell=ScreenCell(left.Position);if(left.Pressed){_dragging=true;_dragStart=cell;UpdatePreview(cell);}else if(_dragging){UpdatePreview(cell);CommitPreview();_dragging=false;}return true;}return false;}
    private GlobalCellCoord ScreenCell(Vector2 screen)=>new(_grid!.WorldToCell(GetViewport().GetCanvasTransform().AffineInverse()*screen));
