    private bool IsValid(GlobalCellCoord cell){if(_construction==null||_query==null||!_query.IsInsideWorld(cell.Value))return false;if(_farm?.Plots.ContainsCell(cell.Value)==true)return false;if(_mode==FloorToolModeV3.Remove)return _construction.Floors.TryGetFloor(cell,out _)||_construction.Floors.TryGetBlueprint(cell,out _);if(_construction.Floors.HasFloor(cell)||_construction.Floors.TryGetBlueprint(cell,out _)||_construction.Floors.TryGetMark(cell,out _))return false;return _query.IsWalkable(cell.Value)||_construction.Structures.IsStructureCell(cell);}
