    public override void _PhysicsProcess(double delta){if(_construction==null||!GameplaySessionV3.IsCurrentConstructionSession(_construction))return;Stopwatch sw=Stopwatch.StartNew();_construction.Floors.ResetTickDiagnostics();ProcessBatches(MaxBlueprintCreatesPerFrame);IReadOnlyList<Vector2I> dirty=_construction.Floors.ConsumeDirtyChunks(MaxFloorVisualChunksPerFrame);_construction.Floors.Diagnostics.VisualChunksUpdatedThisFrame=dirty.Count;if(dirty.Count>0)QueueRedraw();sw.Stop();_construction.Floors.Diagnostics.RuntimeTickMs=sw.Elapsed.TotalMilliseconds;_construction.Floors.Diagnostics.MaxRuntimeTickMs=Math.Max(_construction.Floors.Diagnostics.MaxRuntimeTickMs,sw.Elapsed.TotalMilliseconds);}
    private void ProcessBatches(int cellBudget){int batches=0;while(cellBudget>0&&batches<MaxDesignationBatchesPerFrame&&_batches.Count>0){FloorDesignationBatchV3 batch=_batches.Peek();while(cellBudget>0&&batch.NextIndex<batch.Cells.Count){GlobalCellCoord cell=batch.Cells[batch.NextIndex++];_pendingCells--;cellBudget--;if(batch.Mode==FloorToolModeV3.Build){if(_construction!.FloorDefinitions.TryGet(FloorDefinitionCatalogV3.WoodenFloorId,out var definition)&&definition!=null&&IsValidForBuild(cell)&&_construction.Floors.TryCreateBlueprint(batch.CompanyId,cell,definition,_manager!.WorldBounds,out _,out _))batch.CreatedCount++;else batch.SkippedCount++;}else if(_construction!.Floors.TryGetBlueprint(cell,out var bp)&&bp!=null){if(_constructionWork?.TryCancelFloorBlueprint(bp.BlueprintId,out _)==true)batch.CreatedCount++;else batch.SkippedCount++;}else if(_construction.Floors.TryMarkDemolition(batch.CompanyId,cell,out _,out bool reused,out _)&&!reused)batch.CreatedCount++;else batch.SkippedCount++;}if(batch.NextIndex>=batch.Cells.Count){_batches.Dequeue();batches++;GD.Print($"[FloorV3] batch completed id={batch.BatchId} mode={batch.Mode} created={batch.CreatedCount} skipped={batch.SkippedCount}");}else break;}}
    private bool IsValidForBuild(GlobalCellCoord cell)=>_construction!=null&&_query!=null&&_query.IsInsideWorld(cell.Value)&&_farm?.Plots.ContainsCell(cell.Value)!=true&&!_construction.Floors.HasFloor(cell)&&!_construction.Floors.TryGetBlueprint(cell,out _ )&&!_construction.Floors.TryGetMark(cell,out _)&&(_query.IsWalkable(cell.Value)||_construction.Structures.IsStructureCell(cell));
    public override void _Process(double delta){if(_grid==null)return;Vector2 center=GetViewport().GetCanvasTransform().AffineInverse()*(GetViewportRect().Size*.5f);Vector2I chunk=FloorRegistryV3.ChunkOf(_grid.WorldToCell(center));if(chunk!=_lastViewChunk){_lastViewChunk=chunk;QueueRedraw();}}
    public override void _Draw(){if(_construction==null||_grid==null)return;float tile=_grid.TileSize;Transform2D inv=GetViewport().GetCanvasTransform().AffineInverse();Vector2 a=inv*Vector2.Zero,b=inv*GetViewportRect().Size;Vector2I minCell=_grid.WorldToCell(new(Math.Min(a.X,b.X),Math.Min(a.Y,b.Y))),maxCell=_grid.WorldToCell(new(Math.Max(a.X,b.X),Math.Max(a.Y,b.Y)));Vector2I minChunk=FloorRegistryV3.ChunkOf(minCell),maxChunk=FloorRegistryV3.ChunkOf(maxCell);int drawn=0;for(int cy=minChunk.Y-1;cy<=maxChunk.Y+1&&drawn<MaxFloorVisualCellsPerFrame;cy++)for(int cx=minChunk.X-1;cx<=maxChunk.X+1&&drawn<MaxFloorVisualCellsPerFrame;cx++){Vector2I chunk=new(cx,cy);foreach(var floor in _construction.Floors.EnumerateFloorsInChunk(chunk)){DrawFloor(floor.Cell,tile);drawn++;}foreach(var bp in _construction.Floors.EnumerateBlueprintsInChunk(chunk)){Rect2 r=Rect(bp.Cell,tile);DrawRect(r,new Color(.62f,.45f,.25f,.25f),true);DrawRect(r,new Color(.92f,.73f,.45f,.72f),false,1);drawn++;}foreach(var mark in _construction.Floors.EnumerateMarksInChunk(chunk)){Rect2 r=Rect(mark.Cell,tile);DrawRect(r,new Color(.8f,.1f,.12f,.22f),true);DrawLine(r.Position+new Vector2(4,4),r.End-new Vector2(4,4),new Color(1f,.2f,.2f,.85f),1.5f);DrawLine(new(r.End.X-4,r.Position.Y+4),new(r.Position.X+4,r.End.Y-4),new Color(1f,.2f,.2f,.85f),1.5f);drawn++;}}foreach(var cell in _validPreview)DrawRect(Rect(cell,tile),_mode==FloorToolModeV3.Build?new Color(.35f,.8f,.5f,.28f):new Color(.9f,.2f,.2f,.3f),true);foreach(var cell in _invalidPreview)DrawRect(Rect(cell,tile),new Color(.9f,.1f,.15f,.22f),true);}
